INSERT INTO public.photos VALUES (24534, 'Matadero c.1945', 'Imagen capturada en el patio principal del matadero municipal, a espaldas de la monumental puerta de entrada desde la calle de Miguel Servet, cuya sombra se proyecta sobre la fuente del Buen Pastor. Aparcados en los porches, camiones frigor├¡ficos para distribuci├│n de la carne procesada en este veterano establecimiento en servicio desde 1887.', 1945, 1945, 1945, 'Anos 40', 'SAN JOS├ë', 41.64476000, -0.87007600, '0101000020E6100000971AA19FA9D7EBBF6DE2E47E87D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50078126331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50078126331.webp', 'https://www.flickr.com/photos/zaragozaantigua/50078126331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24701, 'Matadero 1878', 'Alzado del proyecto de Ricardo Magdalena para el matadero municipal de Zaragoza, mayo de 1878. Ser├í inaugurado para albergar la Exposici├│n Aragonesa de 1885. Fuente: AMZ.', 1878, 1878, 1878, 'Siglo XIX', 'SAN JOS├ë', 41.64477600, -0.87006000, '0101000020E61000002BD9B11188D7EBBF739F1C0588D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21087475345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21087475345.webp', 'https://www.flickr.com/photos/zaragozaantigua/21087475345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24568, 'La Granja c.1928', 'Imagen capturada en la Granja Agr├¡cola durante la visita de la Comisi├│n Permanente del ayuntamiento de la ciudad, encabezada por su alcalde, Miguel Allu├® Salvador. Junto a ├®l, el ingeniero-director de la Granja, Jos├® Cruz Lapazar├ín Berista├¡n, les muestra el funcionamiento de una trilla mec├ínica. Fuente visual: exposici├│n ÔÇ£La investigaci├│n agroalimentaria en Arag├│n. Sus inicios con Rodr├¡guez AyusoÔÇØ. Centro de Investigaci├│n y Tecnolog├¡a Agroalimentaria de Arag├│n (CITA).', 1928, 1928, 1928, 'Anos 20', 'SAN JOS├ë', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20110116930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20110116930.webp', 'https://www.flickr.com/photos/zaragozaantigua/20110116930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25138, 'Cementera Miraflores 1945', 'Postal publicitaria con el dibujo de las instalaciones de la f├íbrica de Cementos Portland Zaragoza, en Miraflores. El Pilar de las dos torres, al fondo, referencia universalmente las enormes instalaciones de esta planta, que se extienden delimitadas por las l├¡neas de ferrocarril a Utrillas, y la que conecta Madrid con Barcelona. Fuente: Archivo Enrique Baile.', 1945, 1945, 1945, 'Anos 40', 'SAN JOS├ë', 41.63145000, -0.86343500, '0101000020E6100000A818E76F42A1EBBF9487855AD3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20950434333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20950434333.webp', 'https://www.flickr.com/photos/zaragozaantigua/20950434333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21636, 'Calle de Miguel Servet 1925', 'Reci├®n llegado de los antiguos talleres de Carde y Escoriaza, redenominados Material M├│vil y Construcciones desde principios de los a├▒os veinte, el nov├¡simo coche que inauguraba en los Tranv├¡as de Zaragoza la serie de los "50", revestido de madera para hacer m├ís liviano su peso, y coloreado de amarillo. De fondo, la esquina del antiguo edificio de oficinas y direcci├│n junto al ingreso al cocher├│n de la calle de Miguel Servet, sito en su lado sur e inmediatos a la estaci├│n de Utrillas.', 1925, 1925, 1925, 'Anos 20', 'SAN JOS├ë', 41.63962900, -0.86622400, '0101000020E61000006954E0641BB8EBBF5E49F25CDFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50113666052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50113666052.webp', 'https://www.flickr.com/photos/zaragozaantigua/50113666052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22439, 'Miraflores 1962', 'Imagen de una locomotora a vapor de la MZA, serie 651/680, camino de la estaci├│n de Campo Sepulcro, tras haber pasado por la de Miraflores (al fondo, a la derecha). La imagen se ha capturado desde la altura del puente para tr├ífico rodado que daba continuidad al camino de Cabald├│s. Los campos de esta zona formaban parte de los terrenos de la antigua Granja Agr├¡cola. La estaci├│n de Utrillas queda a la izquierda, fuera de plano. Al fondo, el gran complejo de la cementera de Miraflores, que incluye las chimeneas que emergen de la estaci├│n ferroviaria. Fuente visual: image.slidesharecdn.com/', 1962, 1962, 1962, 'Anos 60', 'SAN JOS├ë', 41.63351300, -0.86909800, '0101000020E6100000B79BE09BA6CFEBBFA14B38F416D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30819877595.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30819877595.webp', 'https://www.flickr.com/photos/zaragozaantigua/30819877595/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22882, 'Estaci├│n de Utrillas 1985', 'Imagen panor├ímica de la antigua estaci├│n de Utrillas, abandonada desde 1966. Hoy esta toma habr├¡a que hacerla desde la calle Valent├¡n Zabala, donde antes se localizaba la gran curva de acceso a la Estaci├│n en que la v├¡a ├║nica de entrada se multiplicaba hasta en ocho viales para conducir tanto al Dep├│sito de locomotoras (los "Arcos" de la izquierda), a los muelles de descarga de mercanc├¡as, a los andenes para depositar/recoger pasaje en el Edificio Principal (a la derecha), al cocher├│n de vagones, y al mar de v├¡as del fondo de la Estaci├│n. Hacia la derecha, otras tres v├¡as conduc├¡an al descargadero de las carboneras, donde la actual calle Bubierca. En la imagen, en primer├¡simo plano, soberan├¡a de aliagas, espartos, ontinas, sisallos, y alguna que otra aspirante a capitana que verdean, aun en blanco y negro, en el espacio de tr├ínsito de las v├¡as del tren. Encima, magn├¡fico y dominante, el exoexqueleto del Dep├│sito de Locomotoras. De ├®l emerge, axial, la Chimenea MFU con matr├¡cula del a├▒o 1925. A su lado, el cementoso dep├│sito de agua ya s├│lo como ocasional criadero de renacuajos/ranas. Sin soluci├│n de continuidad, los muros y enormes farolas de las cocheras de los autobuses urbanos que sustituyeron en ubicaci├│n y trayectos a los tranv├¡as de la ciudad. Estos muros se retranquearon un bastante-m├ís-para-ac├í, aprovechando que el T├¡ber pasa por Roma, ocupando el lugar de las v├¡as del ferrocarril, de forma que cuando se construy├│ el Colegio P├║blico Tom├ís Alvira hubo que retrasar la medianera unas decenas de metros. Gracias a eso hay una continuidad peatonal con la actual plaza de ├üngel Sanz Briz. Al fondo de la imagen, los bloques del Camino de Cabald├│s, antes de urbanizarse con bloques, y nuevos espacios abiertos, como la Plaza Ferm├¡n Aguayo. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/10799465686/in...', 1985, 1985, 1985, 'Anos 80', 'SAN JOS├ë', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19645417384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19645417384.webp', 'https://www.flickr.com/photos/zaragozaantigua/19645417384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22998, 'David Bowie 1997', 'Actuaci├│n del cantante londinense David Bowie (1947-2016) en el pabell├│n deportivo Pr├¡ncipe Felipe de Zaragoza, el mi├®rcoles 16 de julio de 1997. Fuente: Heraldo de Arag├│n.', 1997, 1997, 1997, 'Anos 90', 'SAN JOS├ë', 41.63532000, -0.86619800, '0101000020E61000001A8A3BDEE4B7EBBF533F6F2A52D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24373261365.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24373261365.webp', 'https://www.flickr.com/photos/zaragozaantigua/24373261365/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24475, 'GIESA 1945', 'Puerta principal de acceso a la f├íbrica Guiral Industrias El├®ctricas S.A. (GIESA), terminada de construir en 1945 en la calle Miguel Servet.', 1945, 1945, 1945, 'Anos 40', 'SAN JOS├ë', 41.63948300, -0.86488400, '0101000020E610000060ADDA3521ADEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20986429389.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20986429389.webp', 'https://www.flickr.com/photos/zaragozaantigua/20986429389/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24702, 'Miguel Servet 1927', 'Imagen de la colocaci├│n de tendido a├®reo de cable telef├│nico en la parte derecha de la carretera de Zaragoza a Castell├│n, o Miguel Servet. La foto ha sido capturada entre la calle de Tom├ís Higuera, y la de Belchite. A la derecha, los muros de la estaci├│n de Utrillas y los gemelos edificios de viviendas de la plaza de acceso a la estaci├│n. Al fondo a la izquierda, el palacio de Larrinaga. Fuente visual: foto Alfonso, en Fundaci├│n Telef├│nica.', 1927, 1927, 1927, 'Anos 20', 'SAN JOS├ë', 41.64163200, -0.86773800, '0101000020E6100000E7E26F7B82C4EBBF960854FF20D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21104405094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21104405094.webp', 'https://www.flickr.com/photos/zaragozaantigua/21104405094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22952, 'Actur 1981', 'Ortofoto de Zaragoza de 1981 centrada en el Actur. Fuente: Instituto Geogr├ífico de Arag├│n.', 1981, 1981, 1981, 'Anos 80', 'ACTUR-REY FERNANDO', 41.67519400, -0.88568600, '0101000020E610000042CD902A8A57ECBF4B3ACAC16CD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41430864062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41430864062.webp', 'https://www.flickr.com/photos/zaragozaantigua/41430864062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21598, 'Parque Primo de Rivera 1928', 'Postal. Vista desde el Cabezo de Buenavista del reci├®n redenominado parque Primo de Rivera y su reci├®n construido Rinc├│n de Goya, Fuente: www.ebay.com/', 1928, 1928, 1928, 'Anos 20', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25302397710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25302397710.webp', 'https://www.flickr.com/photos/zaragozaantigua/25302397710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24979, 'Monumento a Pignatelli 1933', 'Monumento a Pignatelli en los ÔÇ£JardinesÔÇØ del mismo nombre, entre la avenida de Wilson (a la izquierda), y la avenida del Siglo XX/paseo de Cu├®llar (derecha). Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.63686900, -0.88504400, '0101000020E61000003BAC70CB4752ECBF096B63EC84D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22875244899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22875244899.webp', 'https://www.flickr.com/photos/zaragozaantigua/22875244899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21820, 'Incendio Tudor 1935', 'Foto: Mar├¡n Chivite. El martes 1 de octubre de 1935 se produjo un incendio en el edificio principal de la f├íbrica de Acumuladores Tudor "La Pilar", aunque continu├│ en funcionamiento en esa ubicaci├│n hasta 1946. En la imagen, labores de extinci├│n desde la avenida de la Rep├║blica (derecha). Tras el bloque incendiado, el paseo de Cu├®llar y el parque Pignatelli, con la c├║pula de la iglesia de San Fernando al fondo. Fuente: Heraldo de Arag├│n.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63940900, -0.88593500, '0101000020E610000061376C5B9459ECBF50E27327D8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31644488321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31644488321.webp', 'https://www.flickr.com/photos/zaragozaantigua/31644488321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22830, 'Plaza de San Francisco 1970', '"Plaza de San Francisco (Monumento a Fernando el Cat├│lico)". ├ôleo sobre lienzo, 73 x 60 cm, Mar├¡a ├üngeles Ca├▒ada, 1970. Al fondo, fachada de los pares del paseo de Fernando el Cat├│lico, desde el n├║mero 32 hacia atr├ís.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64092800, -0.89485900, '0101000020E61000001D007157AFA2ECBF9C8BBFED09D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53637685189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53637685189.webp', 'https://www.flickr.com/photos/zaragozaantigua/53637685189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24541, 'C.┬║ de las Torres 1924', 'Imagen capturada en el vecino solar del taller de canter├¡a de Bayod sito en el arbolado camino de las Torres (a la izquierda, tras la valla) y confrontando con la f├íbrica del acumulador Tudor. En este solar estuvo ubicada una f├íbrica de yeso, y en el momento de realizar la fotograf├¡a se estaban obrando los cimientos de donde habnr├¡a de surgir el notable edificio de Casa Faci, chaflanero con el paseo de Sagasta.', 1924, 1924, 1924, 'Anos 20', 'UNIVERSIDAD', 41.64011800, -0.88620700, '0101000020E61000008A8F4FC8CE5BECBF5CCAF962EFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52170286347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52170286347.webp', 'https://www.flickr.com/photos/zaragozaantigua/52170286347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23129, 'Avenida Goya 2006', 'Foto: M. Mart├¡nez. Vista de la avenida de Goya, con la Gran V├¡a a la izquierda. En el aparcamiento arbolado del centro de la imagen se inaugurar├í en 2012 la estaci├│n ferroviaria de cercan├¡as Zaragoza-Goya. Fuente: Heraldo de Arag├│n.', 2006, 2006, 2006, 'Siglo XXI', 'UNIVERSIDAD', 41.64401100, -0.89141800, '0101000020E6100000721AA20A7F86ECBFD3A1D3F36ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31589489240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31589489240.webp', 'https://www.flickr.com/photos/zaragozaantigua/31589489240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24175, 'Puente sobre el Huerva en Goya 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 18/02/1965. "Nuevo puente sobre el Huerva". El soterramiento de las v├¡as del ferrocarril por la Avenida de Goya, supuso la construcci├│n de un nuevo puente sobre el Huerva, sin nombre. En la imagen, obras de construcci├│n del nuevo puente, con vista de los nuevos t├║neles para el ferrocarril. Al fondo, la pasarela peatonal sobre el r├¡o, que desaparecer├í cuando el nuevo puente est├® terminado.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14981631606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14981631606.webp', 'https://www.flickr.com/photos/zaragozaantigua/14981631606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21599, 'Vista desde la Seo c.1925', 'Postal, Lucien Roisin. Vista de Zaragoza desde la torre de la Seo hacia 1925, con su abigarrado caser├¡o en el entorno del Pilar (a la derecha). Fuente: www.catedu.es', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65556400, -0.87903600, '0101000020E61000008736001B1021ECBFAC376A85E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25499563562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25499563562.webp', 'https://www.flickr.com/photos/zaragozaantigua/25499563562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24945, 'Parque Primo de Rivera c.1974', 'Fuentes en el paseo de San Sebasti├ín del parque Primo de Rivera. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63486400, -0.89440000, '0101000020E6100000575BB1BFEC9EECBF31B43A3943D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27143364480.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27143364480.webp', 'https://www.flickr.com/photos/zaragozaantigua/27143364480/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25120, 'Colegio mayor Cardenal Xavierre 1943', 'Dibujo del proyecto de Lorenzo Moncl├║s del edificio del Colegio mayor Cardenal Xavierre, ejecutado en 1948 junto al campus universitario de la plaza de San Francisco entre las calles de Pedro Cerbuna y Baltasar Graci├ín. Ni el edificio de su izquierda ni el arco de su derecha existen o existieron nunca. Fuente: Zaragoza 1908-2008. FCC.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64168000, -0.89563200, '0101000020E6100000C808A87004A9ECBFA73FFB9122D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15524713978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15524713978.webp', 'https://www.flickr.com/photos/zaragozaantigua/15524713978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
