INSERT INTO public.photos VALUES (21945, 'Torre├│n de la Zuda a├▒os 40', 'Torre├│n de la Zuda, aguafuerte, Jes├║s Fern├índez Barrio, Diputaci├│n de Zaragoza, c. 1945-1947. Al fondo, Mercado Central. Fuente: web.dpz.es/arscatalogi.es/', 1940, 1940, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15876909915.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15876909915.webp', 'https://www.flickr.com/photos/zaragozaantigua/15876909915/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21780, 'La Lonja 1932', 'La Lonja desde el paseo de la Ribera. A la izquierda, la calle de Don Jaime I. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65588600, -0.87624900, '0101000020E6100000F3E2C4573B0AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22953545510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22953545510.webp', 'https://www.flickr.com/photos/zaragozaantigua/22953545510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22378, 'Vista a├®rea Parque Grande 1964', 'Vista parcial del parque Primo de Rivera de Zaragoza y del antiguo ensanche de Miralbueno, hoy Universidad. Al fondo, el norte de la ciudad. Fuente: Colecci├│n Rafael Margal├®.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22290228726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22290228726.webp', 'https://www.flickr.com/photos/zaragozaantigua/22290228726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22450, 'Vista &quot;Casa Grande&quot; 1960', '"Vista panor├ámica d''un bloc d''habitatges a la ciutat de Saragossa." Desde GAZA entendemos que se trata de una a├®rea visual centrada en la Residencia Sanitaria "Jos├® Antonio", en el paseo de Isabel la Cat├│lica. Al fondo, campos de cultivo. Adem├ís, gratis et amore, desde GAZA hemos volteado horizontalmente la imagen original para tratar de orientar la vista de forma adecuada. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63516400, -0.90013200, '0101000020E610000087A8C29FE1CDECBF5CCCCF0D4DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31241373871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31241373871.webp', 'https://www.flickr.com/photos/zaragozaantigua/31241373871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20900, 'Venida de la Virgen a├▒o 40', '"Venida de la Virgen del Pilar a Zaragoza", Maestro de Luesia, c 1490. Sarga pintada al temple que representa la llegada de Mar├¡a a la ciudad, acompa├▒ada de ├íngeles cantores, la madrugada del 2 de enero del a├▒o 40, lunes. Se conserva en la sacrist├¡a de la bas├¡lica del Pilar. A la izquierda de la columna, el ap├│stol Santiago con sus correligionarios. Detr├ís, el r├¡o Ebro y el Arrabal, con sus bosques y campos de cultivo. Fuente: eszaragoza.blogspot.com.es/', NULL, NULL, NULL, NULL, 'CASCO HIST├ôRICO', 41.65697100, -0.87824500, '0101000020E610000043041C42951AECBFD0B52FA017D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30696808570.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30696808570.webp', 'https://www.flickr.com/photos/zaragozaantigua/30696808570/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21658, 'Estaci├│n Campo Sepulcro 1927', 'In├®dita imagen capturada en el acceso a la estaci├│n de Campo Sepulcro con motivo de la llegada a Zaragoza del Infante don Jaime de Borb├│n y Battenberg al objeto de inaugurar, en representaci├│n de su padre Alfonso XIII, la Exposici├│n Regional Av├¡cola ubicada en la Lonja. Su espigada Alteza aparece flanqueada por el Alcalde Allu├® Salvador y el capit├ín general Perales Vallejo, y rodeado por buen n├║mero de no menos altos representantes militares, religiosos y civiles locales. Su apretada agenda de actividades programada para la tarde de ese d├¡a incluy├│ la preceptiva participaci├│n en un Tedeum en el templo del Pilar; la visita en el campamento de Alfonso XIII de los terrenos previstos para acoger la Academia General Militar; la asistencia a la final de la Copa del Rey en el campo del Iberia que disputaron el Arenas Club de Guecho y el Real Uni├│n Club de Ir├║n (que resultar├¡a vencedor por un tanto a cero). Despu├®s inaugur├│ la referida Exposici├│n Av├¡cola y se desplaz├│ a la Casa Consistorial donde firm├│ el Libro de Oro de la Ciudad y fue agasajado con un "lunch". Finalmente, regres├│ a la estaci├│n de Campo Sepulcro donde se subi├│ a un "break" agregado al tren correo de Madrid para hacer el viaje de vuelta a esa villa.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.65234900, -0.89480600, '0101000020E61000006877483140A2ECBF064A0A2C80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53210201584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53210201584.webp', 'https://www.flickr.com/photos/zaragozaantigua/53210201584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21974, 'Campo Sepulcro 1941', 'Entre 1941 y 1943, la estaci├│n de ferrocarril de Campo Sepulcro fue un nudo de comunicaci├│n muy importante para la ordenaci├│n y clasificaci├│n de los voluntarios falangistas que configuraron la denominada "Divisi├│n Azul", encuadrada como 250┬¬ divisi├│n de infanter├¡a de la Wermacht durante la agresi├│n armada del III Reich alem├ín contra la Uni├│n Sovi├®tica. Zaragoza fue lugar de paso de convoyes procedentes de Andaluc├¡a, las dos Castillas, Valencia, e incluso de Catalu├▒a, en su ruta, bien hacia el paso por Hendaya, bien al de Port-Bou. Y lo hizo en las dos direcciones, tanto de salida hacia el frente ruso, como de llegada de los "retornados". Hubo tambi├®n un part├¡cipe contingente zaragozano. En la imagen, nocturno paso por al estaci├│n de ferrocarril de Campo Sepulcro de uno de los primeros convoyes de voluntarios falangistas con destino a Rusia, presumiblemente de voluntarios manchegos en su paso hacia Hendaya. Una breve parada, camino de seguir combatiendo contra el comunismo (ahora directamente en su cubil, pues comulgaban con la consigna "Rusia es culpable"), es aprovechada para reafirmar sus predispuestas convicciones ideol├│gicas. Banderas al viento, c├ínticos cuarteleros, y vivas al caudillo, al duce y al f├╝hrer, alimento espiritual de estos autoproclamados cruzados del fascismo. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1941, 1941, 1941, 'Anos 40', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24441554504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24441554504.webp', 'https://www.flickr.com/photos/zaragozaantigua/24441554504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22132, 'Campo Sepulcro 1956', 'Imagen en altura de un grupo de unidades ferroviarias el├®ctricas 1500v de la serie 433, (denominadas "Ping├╝inos") producidas para la RENFE en la factor├¡a de Material M├│vil y Construcciones. Al fondo, la estaci├│n de Campo Sepulcro, y m├ís al fondo, los grandes bloques de viviendas militares de la manzana entre Anselmo Clav├® y el paseo de Mar├¡a Agust├¡n. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ)', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65196900, -0.89757100, '0101000020E610000007D15AD1E6B8ECBFBF805EB873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23946424076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23946424076.webp', 'https://www.flickr.com/photos/zaragozaantigua/23946424076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22136, 'C.┬║ de la Romareda 1959', 'Foto capturada en el ingreso principal de las oficinas de VIASA (Veh├¡culos Industriales y Agr├¡colas SA) proyectadas por el arquitecto Jos├® de Yarza Garc├¡a en el antiguo camino de la Romareda, reci├®n redenominado calle Manuel Escoriaza y Fabro (el n┬║ 103) y esquinera con la de Vicente Berdus├ín. Esta factor├¡a hab├¡a sido construida entre 1957-58 como ap├®ndice empresarial de Material M├│vil y Construcciones (Antiguos Talleres de Carde y Escoriaza) para la construcci├│n bajo licencia en Espa├▒a de la norteamericana marca de autom├│vil todoterreno Jeep. Hacia la izquierda, fuera de plano, el inmediato mar de v├¡as de la estaci├│n de ferrocarril Campo Sepulcro. Fuente visual: arch. J. de Yarza', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65370100, -0.89790000, '0101000020E61000004182E2C798BBECBF662E7079ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24298626768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24298626768.webp', 'https://www.flickr.com/photos/zaragozaantigua/24298626768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22168, 'Vista VIASA 1959', 'Vista a├®rea centrada en la factor├¡a VIASA (Veh├¡culos Industriales y Agr├¡colas, S.A.), ap├®ndice empresarial de Material M├│vil y Construcciones, parte de cuyas naves se ven abajo. Por el mismo precio, y a su justo lado, las grandes naves de ALSOVISA (Alfonso Solans Viamonte, S.A.), f├íbrica de camas met├ílicas y somieres, sita en la calle de Blanca de Navarra. A la derecha, mar de v├¡as de la estaci├│n Campo Sepulcro. Al fondo, el r├¡o Ebro. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65370100, -0.89790000, '0101000020E61000004182E2C798BBECBF662E7079ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31212708832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31212708832.webp', 'https://www.flickr.com/photos/zaragozaantigua/31212708832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22169, 'Vista a├®rea Delicias 1959', 'Imagen a├®rea desde el barrio de Las Delicias, con la iglesia de San Valero abajo, y en el centro el gran complejo de Material M├│vil y Construcciones. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65140800, -0.89985300, '0101000020E6100000BEA3C68498CBECBF282D5C5661D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31315606756.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31315606756.webp', 'https://www.flickr.com/photos/zaragozaantigua/31315606756/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22170, 'Calle Unceta 1956', 'Imagen de la fachada de la Escuela de Formaci├│n Profesional San Valero, cuyos primeros pasos databan de 1952, en el entorno de la vecina parroquia de San Valero (barrio de las Delicias), como escuela de capacitaci├│n profesional para peones y aprendices. En 1954 fue inaugurado el primer taller escuela por el arzobispo Domenech y Valls, y en 1956 su sucesor, el arzobispo Morcillo, inaugur├│ la ampliaci├│n, en esa misma ubicaci├│n. En la imagen, tras el singular grupo ciclista (posiblemente de alumnos y profesores), fachada de la escuela, en el n┬║ 11-13 de la calle de Unceta. A la izquierda, fuera de plano, la calle del Padre Manj├│n (antigua de Marcelino Domingo). A su derecha, las antiguas parcelas de los n├║meros 15, y 17. Al otro lado de la calle, fuera de plano, la parroquia de San Valero, esquinera con la calle de Graus. Fuente visual: www.sanvalero.es/', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65308400, -0.90233600, '0101000020E6100000501C40BFEFDFECBF3BC5AA4198D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31333893032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31333893032.webp', 'https://www.flickr.com/photos/zaragozaantigua/31333893032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22261, 'Talleres Carde y Escoriaza c.1961', 'Vista a├®rea de la zona ocupada por los talleres Carde y Escoriaza, en los terrenos donde se construy├│ luego la urbanizaci├│n Parque Roma. Tras la factor├¡a, se pueden ver las instalaciones de la estaci├│n Campo Sepulcro, y m├ís all├í el cuartel del Cid junto a la plaza de Toros, llegando la visual incluso al r├¡o Ebro.', 1961, 1961, 1961, 'Anos 60', 'DELICIAS', 41.65196900, -0.89757100, '0101000020E610000007D15AD1E6B8ECBFBF805EB873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14781681738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14781681738.webp', 'https://www.flickr.com/photos/zaragozaantigua/14781681738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22323, 'Estaci├│n Campo Sepulcro c.1967', 'Imagen capturada desde la altura de los bloques de vivienda militar de la calle Anselmo Clav├®, del acceso desde ese vial a la estaci├│n de ferrocarril de Campo Sepulcro. A la izquierda, el dep├│sito de locomotoras. A la derecha, talleres de la estaci├│n. Al fondo, el edificio central. Detr├ís, el complejo industrial de Carde y Escoriaza. Fuente visual: www.facebook.com/photo.php?fbid=879812342051965&set=p...', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65210400, -0.89413500, '0101000020E6100000CDAFE600C19CECBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15987338746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15987338746.webp', 'https://www.flickr.com/photos/zaragozaantigua/15987338746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22405, 'Campo Sepulcro 1968', 'Imagen del and├®n principal de la estaci├│n de ferrocarril de Campo Sepulcro, cuando ya era denominada extraoficialmente "Estaci├│n de Madrid" para evitar la referencia a la cadaverina que dio pie a la denominaci├│n de ese entorno desde los tiempos de alguno de los Carolo. La esquivez con este aspecto de la tradici├│n y el esp├¡ritu "detodalavida" que impregna la ciudad, se argumentaba por motivos tur├¡sticos, de falta de atractivo del nombre. Cuando unos a├▒os despu├®s la estaci├│n fue remozada integralmente, en el paquete entr├│ tambi├®n un nuevo nomencl├ítor para ella (Portillo), aunque ello supusiera violentar las coordenadas de esta ubicaci├│n, extendi├®ndola hasta donde antes nunca llegara. Pero el turismo mejor├│, y la modernidad se precipit├│ sobre la ciudad como nunca antes. En la imagen, otra de esas escenas de la Espa├▒a que no luc├¡a: maletas de cart├│n y cajas atadas con cuerdas, portadas por personas sin glamour ni estilo. Como nosotros. Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65241500, -0.89512900, '0101000020E610000019709692E5A4ECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24244362520.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24244362520.webp', 'https://www.flickr.com/photos/zaragozaantigua/24244362520/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22467, 'Campo Sepulcro 1968', 'Imagen centrada en una locomotora 4-8-2 que, junto a otras estacionadas, maniobra en el ├írea descubierta del dep├│sito de la estaci├│n Zaragoza-Campo Sepulcro, entre el edificio de la estaci├│n (al fondo), y Anselmo Clav├® (a la derecha, fuera de plano). Fuente visual: foto Bernard Harrison, en www.flickr.com/photos/30937/19479014850/', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65221000, -0.89485300, '0101000020E6100000954737C2A2A2ECBFE40F069E7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32903066464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32903066464.webp', 'https://www.flickr.com/photos/zaragozaantigua/32903066464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22473, 'Campo Sepulcro 1968', 'Imagen centrada en dos locomotoras (posiblemente, "Santa Fe") estacionadas en el ├írea cubierta del dep├│sito de la estaci├│n Zaragoza-Campo Sepulcro. Al fondo, los bloques de viviendas para militares de Anselmo Clav├®. Fuente visual: foto Bernard Harrison, en www.flickr.com/photos/30937/19671464931/', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65221000, -0.89485300, '0101000020E6100000954737C2A2A2ECBFE40F069E7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33623233581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33623233581.webp', 'https://www.flickr.com/photos/zaragozaantigua/33623233581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22510, 'Campo Sepulcro c.1965', 'Imagen de los talleres de la estaci├│n de ferrocarril de Campo Sepulcro, con varias locomotoras a vapor de la serie 2400 en tareas de mantenimiento y reparaci├│n. Estos talleres estaban radicados junto al dep├│sito de locomotoras, a la altura de la calle de Madre Sacramento. Al fondo, el cuartel de la Polic├¡a Armada de la avenida de Anselmo Clav├®. Cuando la estaci├│n fue remodelada, pocos a├▒os despu├®s, sobre estos talleres se construy├│ el edificio del Centro de clasificaci├│n postal de Correos.', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65125400, -0.89416200, '0101000020E6100000336E6AA0F99CECBFD1B1834A5CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51016543032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51016543032.webp', 'https://www.flickr.com/photos/zaragozaantigua/51016543032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22541, 'Delicias Este 1973', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 24/04/1973. Vista en altura desde uno de los nuevos bloques de viviendas de la Avenida de Madrid, de c├│mo estaban las cosas en esta parte del Barrio de las Delicias, concretamente en las traseras de la Estaci├│n de El Portillo, reci├®n estrenada su remodelaci├│n integral, incluyendo el nombre. Proliferaci├│n de naves industriales, sobre todo de los gigantescos talleres de Carde y Escoriaza, inmediatos a la Estaci├│n, que hoy dan nombre a la larga calle que por all├¡ circula. Abajo, y peque├▒itas, las parcelas de las calles del entorno, como Do├▒a Blanca de Navarra (en medio de la imagen), que desde la Avenida de Madrid conectaba con esta zona. Otras calles: Navas de Tolosa, Tenor Gayarre, Bolivia... Tras el traslado de las naves a pol├¡gonos industriales m├ís lejanos, esa zona se urbaniz├│ y modific├│ mucho.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65194300, -0.89825000, '0101000020E61000005839B4C876BEECBF96ED43DE72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14937650406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14937650406.webp', 'https://www.flickr.com/photos/zaragozaantigua/14937650406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20878, 'Castillo de Miranda s. XII', 'Reconstrucci├│n virtual de Daniel Herrera del estado original del castillo de Miranda, en el barrio de Juslibol de Zaragoza. Fuente: deuslovol.blogspot.com.es/', 1150, 1100, 1199, 'Siglo XIX', NULL, 41.70776800, -0.92423200, '0101000020E61000006155BDFC4E93EDBFE2934E2498DA4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19843375686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19843375686.webp', 'https://www.flickr.com/photos/zaragozaantigua/19843375686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22546, 'Estaci├│n del Portillo 1973', '1973. La estaci├│n de Campo Sepulcro fue ampliada y reformada profundamente por RENFE, y rebautizada como Zaragoza-El Portillo, concentrando todos los servicios que hasta ese momento prestaban las estaciones de Campo Sepulcro, Delicias, y Arrabal. En la imagen, casi resplandece la nueva estaci├│n. Al fondo, naves de Carde y Escoriaza. A la derecha, el acceso a la antigua estaci├│n de Campo Sepulcro fue reaprovechado para acceso al aparcamiento "subterr├íneo". En el centro, donde estuvo el dep├│sito de locomotoras de la antigua estaci├│n, el elevado acceso a la nueva Estaci├│n, con la parada de taxis y el aparcamiento en superficie.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65183100, -0.89409800, '0101000020E61000008368AD68739CECBF6EC2BD326FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14978837241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14978837241.webp', 'https://www.flickr.com/photos/zaragozaantigua/14978837241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22565, 'Zaragoza-El Portillo 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 22/09/1974. Imagen de la estaci├│n de ferrocarril "Zaragoza-El Portillo", con su rampa de acceso para veh├¡culos y peatones. El edificio hab├¡a sido proyectado por Demetrio Ullastres y Alfredo Mart├¡nez Alonso, y levantado en 1971. Obtuvo el Trofeo Ricardo Magdalena de 1972. Esta rampa estaba construida en el lugar del dep├│sito de locomotoras de vapor de la anterior estaci├│n Campo Sepulcro.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65183100, -0.89409800, '0101000020E61000008368AD68739CECBF6EC2BD326FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15231688809.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15231688809.webp', 'https://www.flickr.com/photos/zaragozaantigua/15231688809/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22592, 'De Campo Sepulcro, a Portillo 1970', 'En 1967, la Estaci├│n Campo Sepulcro pas├│ a ser la principal estaci├│n ferroviaria de la ciudad. En 1970, RENFE procedi├│ a su ampliaci├│n y reforma, modificando sustancialmente su aspecto, y cambiando su denominaci├│n por la de "Zaragoza-El Portillo", nombre menos "mortuorio" y de m├ís "atractivo tur├¡stico" (┬┐?) Inaugurada en 1973, estuvo activa hasta 2003. En la imagen, estado de las obras de la nueva estaci├│n sobre el espacio de la antigua, a├║n en pie. El antiguo dep├│sito de locomotoras, ya ha sido derribado. Fuente visual: RENFE', 1970, 1970, 1970, 'Anos 70', 'DELICIAS', 41.65174300, -0.89461300, '0101000020E610000043723271ABA0ECBFCF328B506CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16370010694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16370010694.webp', 'https://www.flickr.com/photos/zaragozaantigua/16370010694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22595, 'Estaci├│n Campo Sepulcro-Portillo 1970', 'Vista a├®rea del proceso de transici├│n entre la Estaci├│n de ferrocarril de Campo Sepulcro, y la de "Zaragoza-El Portillo". En marzo de 1970 se derrib├│ el antiguo Dep├│sito de locomotoras "vaporosas", en cuyo solar se levant├│ el plano inclinado de acceso al caj├│n de la nueva estaci├│n. La nueva estaci├│n, cuya traza original es obra de los ingenieros Demetrio Ullastres y Alfredo Mart├¡nez Alonso, fue Premio Ricardo Magdalena 1972. Las obras avanzaban r├ípidamente, y a finales de 1970 este era el estado de las mismas. Mientras, la antigua estaci├│n segu├¡a siendo utilizada (plano parcial de la misma, a la derecha). Tambi├®n estaba en obras el nuevo centro de clasificaci├│n postal "Zaragoza-Portillo", y en el entorno se levantaban nuevos bloques de viviendas. A├║n en pie, a la izquierda, la antigua Casa de Convalecientes, desde 1968 Colegio Polit├®cnico Nuestra Se├▒ora del Pilar. Al aire, sin cubrir, el pedazo de trinchera ferroviaria entre la calle Santander, y avenida de Valencia. Fuente visual: RENFE.', 1970, 1970, 1970, 'Anos 70', 'DELICIAS', 41.65183100, -0.89409800, '0101000020E61000008368AD68739CECBF6EC2BD326FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16810505748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16810505748.webp', 'https://www.flickr.com/photos/zaragozaantigua/16810505748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22610, 'Vicente Berdus├ín 1975', 'Imagen de la r├ípida transici├│n de un espacio industrial, a otro residencial. Al fondo, la Urbanizaci├│n "Parque Roma" avanza desde la nov├¡sima Plaza de Roma, conforme desaparecen las imponentes naves de la antigua f├íbrica de Escoriaza. Estas instalaciones fabriles de tipo pesado, entre 1920 y 1969 denominadas "Material M├│vil y Construcciones", forman parte absolutamente central en la historia de los ferrocarriles peninsulares. Al comienzo de los a├▒os 60 del pasado siglo, ocupaba 100.000 metros cuadrados, y daba trabajo a 1300 personas, aunque un proceso de fusi├│n empresarial posterior supuso abandonar y vender esta zona entre 1970-73, y trasladarse a un nueva ubicaci├│n en la Avenida de Catalu├▒a. La imagen ha sido capturada desde la calle Vicente Berdus├ín.', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.65132600, -0.89829300, '0101000020E61000002A3927F6D0BEECBF6A847EA65ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19171127305.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19171127305.webp', 'https://www.flickr.com/photos/zaragozaantigua/19171127305/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23032, 'Avenida de Madrid 1992', 'La avenida de Madrid, en el punto donde confluye el denso tr├ífico proveniente de la calle de Marcelino Unceta, a la derecha y fuera de plano. Al fondo, vista parcial del paso elevado met├ílico en el entorno de la Aljafer├¡a. En 2003 se termin├│ la reforma de esta v├¡a de 2 km, ensanchando sus aceras y reservando la direcci├│n hacia el centro de la ciudad para los autobuses.', 1992, 1992, 1992, 'Anos 90', 'DELICIAS', 41.65397000, -0.90277700, '0101000020E61000007D9752978CE3ECBF5648F949B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207294182.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207294182.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207294182/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
